import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Send, Bot, User as UserIcon, Paperclip, FileText, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import * as pdfjsLib from 'pdfjs-dist';
import { toast } from "sonner";

// Use safe worker loading for Vite
import pdfWorker from 'pdfjs-dist/build/pdf.worker.mjs?url';
pdfjsLib.GlobalWorkerOptions.workerSrc = pdfWorker;

interface Message {
    id: string;
    role: "user" | "assistant";
    content: string;
    timestamp: Date;
}

export const Chat = () => {
    const [messages, setMessages] = useState<Message[]>([
        {
            id: "1",
            role: "assistant",
            content: "Hello! I'm your H&L Assistant. You can upload a PDF to chat about its content!",
            timestamp: new Date()
        }
    ]);
    const [input, setInput] = useState("");
    const [isTyping, setIsTyping] = useState(false);
    const [fileContext, setFileContext] = useState<{ name: string, content: string } | null>(null);
    const scrollRef = useRef<HTMLDivElement>(null);
    const bottomRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (bottomRef.current) {
            bottomRef.current.scrollIntoView({ behavior: "smooth" });
        }
    }, [messages]);

    const extractTextFromPDF = async (file: File) => {
        try {
            const arrayBuffer = await file.arrayBuffer();
            const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
            let fullText = "";

            for (let i = 1; i <= pdf.numPages; i++) {
                const page = await pdf.getPage(i);
                const textContent = await page.getTextContent();
                const pageText = textContent.items.map((item: { str: string } | any) => item.str).join(" ");
                fullText += pageText + "\n";
            }

            setFileContext({ name: file.name, content: fullText });
            toast.success(`Loaded "${file.name}" context!`);

            setMessages(prev => [...prev, {
                id: Math.random().toString(36).substring(7),
                role: "assistant",
                content: `I've read "${file.name}". Ask me anything about it!`,
                timestamp: new Date()
            }]);

        } catch (error) {
            console.error("PDF reading error:", error);
            toast.error("Failed to read PDF. Make sure it's a valid file.");
        }
    };

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            if (file.type !== "application/pdf") {
                toast.error("Only PDF files are supported for now.");
                return;
            }
            extractTextFromPDF(file);
        }
    };

    const handleSend = () => {
        if (!input.trim()) return;

        const userMessage: Message = {
            id: Math.random().toString(36).substring(7),
            role: "user",
            content: input,
            timestamp: new Date()
        };

        setMessages(prev => [...prev, userMessage]);
        setInput("");
        setIsTyping(true);

        // Simulate AI RAG response
        setTimeout(() => {
            let response = "That's an interesting question. I'd typically verify that with your study materials.";

            if (fileContext) {
                const keywords = input.toLowerCase().split(" ").filter(w => w.length > 3);
                const found = keywords.some(k => fileContext.content.toLowerCase().includes(k));

                if (found) {
                    response = `Based on "${fileContext.name}", I found relevant information regarding your query. The document discusses this topic in detail. (Mock RAG: In a real implementation, I would send the file text to an LLM to generate this answer).`;
                } else {
                    response = `I checked "${fileContext.name}", but I couldn't find a specific mention of that. Can you rephrase or ask about something else covered in the document?`;
                }
            }

            const aiMessage: Message = {
                id: Math.random().toString(36).substring(7),
                role: "assistant",
                content: response,
                timestamp: new Date()
            };
            setMessages(prev => [...prev, aiMessage]);
            setIsTyping(false);
        }, 1500);
    };

    const handleKeyPress = (e: React.KeyboardEvent) => {
        if (e.key === "Enter" && !e.shiftKey) {
            e.preventDefault();
            handleSend();
        }
    };

    return (
        <div className="h-[calc(100vh-120px)] flex flex-col max-w-4xl mx-auto">
            <div className="mb-4 flex justify-between items-center">
                <div>
                    <h1 className="text-3xl font-bold text-foreground">AI Tutor</h1>
                    <p className="text-muted-foreground">Context-aware help for your studies</p>
                </div>
                {fileContext && (
                    <div className="flex items-center gap-2 px-3 py-1 bg-primary/10 rounded-full text-xs text-primary animate-in fade-in slide-in-from-right-5">
                        <FileText className="w-3 h-3" />
                        <span className="max-w-[150px] truncate">{fileContext.name}</span>
                        <button onClick={() => setFileContext(null)} className="hover:text-destructive transition-colors">
                            <X className="w-3 h-3" />
                        </button>
                    </div>
                )}
            </div>

            <Card className="flex-1 flex flex-col overflow-hidden glass-card">
                <ScrollArea className="flex-1 p-6" ref={scrollRef}>
                    <div className="space-y-6">
                        {messages.map((message) => (
                            <motion.div
                                key={message.id}
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                className={`flex gap-4 ${message.role === "user" ? "flex-row-reverse" : "flex-row"}`}
                            >
                                <Avatar className={`w-10 h-10 border-2 ${message.role === "assistant" ? "border-primary" : "border-muted"}`}>
                                    <AvatarFallback className={message.role === "assistant" ? "bg-primary/10 text-primary" : "bg-muted"}>
                                        {message.role === "assistant" ? <Bot className="w-6 h-6" /> : <UserIcon className="w-6 h-6" />}
                                    </AvatarFallback>
                                </Avatar>

                                <div className={`flex flex-col max-w-[80%] space-y-1 ${message.role === "user" ? "items-end" : "items-start"}`}>
                                    <div
                                        className={`p-4 rounded-2xl text-sm leading-relaxed ${message.role === "user"
                                            ? "bg-primary text-primary-foreground rounded-tr-sm"
                                            : "bg-secondary text-secondary-foreground rounded-tl-sm"
                                            }`}
                                    >
                                        {message.content}
                                    </div>
                                    <span className="text-[10px] text-muted-foreground px-1">
                                        {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                    </span>
                                </div>
                            </motion.div>
                        ))}

                        {isTyping && (
                            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="flex gap-4">
                                <Avatar className="w-10 h-10 border-2 border-primary">
                                    <AvatarFallback className="bg-primary/10 text-primary">
                                        <Bot className="w-6 h-6" />
                                    </AvatarFallback>
                                </Avatar>
                                <div className="bg-secondary p-4 rounded-2xl rounded-tl-sm flex items-center gap-1">
                                    <div className="w-2 h-2 bg-foreground/50 rounded-full animate-bounce" style={{ animationDelay: "0ms" }} />
                                    <div className="w-2 h-2 bg-foreground/50 rounded-full animate-bounce" style={{ animationDelay: "150ms" }} />
                                    <div className="w-2 h-2 bg-foreground/50 rounded-full animate-bounce" style={{ animationDelay: "300ms" }} />
                                </div>
                            </motion.div>
                        )}
                        <div ref={bottomRef} />
                    </div>
                </ScrollArea>

                <div className="p-4 border-t bg-background/50 backdrop-blur-sm">
                    <div className="flex gap-2 relative">
                        <input
                            type="file"
                            ref={fileInputRef}
                            className="hidden"
                            accept=".pdf"
                            onChange={handleFileSelect}
                        />
                        <Button
                            variant="ghost"
                            size="icon"
                            className="text-muted-foreground hover:text-foreground"
                            onClick={() => fileInputRef.current?.click()}
                            title="Attach PDF context"
                        >
                            <Paperclip className="w-5 h-5" />
                        </Button>
                        <Input
                            placeholder="Ask a question..."
                            className="pr-12"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            onKeyDown={handleKeyPress}
                            disabled={isTyping}
                        />
                        <Button
                            size="icon"
                            className="absolute right-1 top-1 h-8 w-8"
                            onClick={handleSend}
                            disabled={!input.trim() || isTyping}
                        >
                            <Send className="w-4 h-4" />
                        </Button>
                    </div>
                </div>
            </Card>
        </div>
    );
};

import { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { Upload, FileText, Youtube, Search, Trash2, ExternalLink, Loader2 } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";

import { Database } from "@/integrations/supabase/types";

type Material = Database['public']['Tables']['materials']['Row'];

export const Materials = () => {
  const [materials, setMaterials] = useState<Material[]>([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [isUploading, setIsUploading] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    fetchMaterials();
  }, []);

  const fetchMaterials = async () => {
    try {
      const { data, error } = await supabase
        .from("materials")
        .select("*")
        .order("created_at", { ascending: false });

      if (error) throw error;
      setMaterials(data as Material[] || []);
    } catch (error) {
      console.error("Error fetching materials:", error);
      toast.error("Failed to load materials");
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.type !== "application/pdf") {
      toast.error("Only PDF files are supported");
      return;
    }

    setIsUploading(true);
    try {
      const fileExt = file.name.split(".").pop();
      const fileName = `${Math.random()}.${fileExt}`;
      const filePath = `${fileName}`;

      // 1. Upload to Storage
      const { error: uploadError } = await supabase.storage
        .from("materials")
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      // 2. Get Public URL
      const { data: { publicUrl } } = supabase.storage
        .from("materials")
        .getPublicUrl(filePath);

      // 3. Save Metadata to DB (using existing schema columns)
      const { data: newMaterial, error: dbError } = await supabase
        .from("materials")
        .insert({
          title: file.name,
          type: "pdf",
          url: publicUrl,
          // user_id is automatically handled by RLS/default value usually, but if needed we can try to omit it or fetch from session
        })
        .select()
        .single();

      if (dbError) throw dbError;

      setMaterials([newMaterial as Material, ...materials]);
      toast.success("File uploaded successfully!");
    } catch (error) {
      console.error("Upload error:", error);
      const message = error instanceof Error ? error.message : "Unknown error";
      const statusCode = (error as any)?.statusCode; // safe check if needed or just remove if unused

      if (message.includes("Bucket not found") || statusCode === "404") {
        toast.error("Storage bucket not found", {
          description: "Please creating a public bucket named 'materials' in your Supabase dashboard."
        });
      } else {
        toast.error(message || "Failed to upload file");
      }
    } finally {
      setIsUploading(false);
    }
  };

  const handleAddYoutube = async () => {
    const url = prompt("Enter YouTube URL:");
    if (!url) return;

    if (!url.includes("youtube.com") && !url.includes("youtu.be")) {
      toast.error("Invalid YouTube URL");
      return;
    }

    try {
      const { data: newMaterial, error } = await supabase
        .from("materials")
        .insert({
          title: "New Video Resource",
          type: "youtube",
          url: url,
        })
        .select()
        .single();

      if (error) throw error;

      setMaterials([newMaterial as Material, ...materials]);
      toast.success("YouTube link added!");
    } catch (error) {
      console.error("Error adding youtube video:", error);
      toast.error("Failed to add video");
    }
  };

  const handleDelete = async (id: string) => {
    try {
      const { error } = await supabase.from("materials").delete().eq("id", id);
      if (error) throw error;

      setMaterials(materials.filter(m => m.id !== id));
      toast.success("Material removed");
    } catch (error) {
      toast.error("Failed to delete material");
    }
  };

  const filteredMaterials = materials.filter(m =>
    m.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const container = {
    hidden: { opacity: 0 },
    show: {
      opacity: 1,
      transition: { staggerChildren: 0.1 }
    }
  };

  const item = {
    hidden: { opacity: 0, y: 20 },
    show: { opacity: 1, y: 0 }
  };

  if (isLoading) {
    return <div className="flex justify-center p-12"><Loader2 className="animate-spin text-primary" /></div>;
  }

  return (
    <motion.div
      variants={container}
      initial="hidden"
      animate="show"
      className="space-y-6"
    >
      <motion.div variants={item} className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold text-foreground">Learning Materials</h1>
          <p className="text-muted-foreground">Manage your PDFs and video resources</p>
        </div>
        <div className="flex gap-2">
          <Button onClick={handleAddYoutube} variant="outline" className="gap-2">
            <Youtube className="w-4 h-4" />
            Add Video
          </Button>
          <div className="relative">
            <input
              type="file"
              accept=".pdf"
              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
              onChange={handleFileUpload}
              disabled={isUploading}
            />
            <Button className="gap-2">
              <Upload className="w-4 h-4" />
              {isUploading ? "Uploading..." : "Upload PDF"}
            </Button>
          </div>
        </div>
      </motion.div>

      {/* Search */}
      <motion.div variants={item} className="relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
        <Input
          placeholder="Search materials..."
          className="pl-10 bg-background/50 border-input"
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
      </motion.div>

      {/* Materials Grid */}
      <motion.div variants={item} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredMaterials.map((material) => (
          <motion.div key={material.id} layout initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
            <Card className="hover:shadow-lg transition-all duration-300 border-border/50 bg-card/50 backdrop-blur-sm">
              <CardHeader className="flex flex-row items-start justify-between pb-2">
                <div className="p-2 rounded-lg bg-primary/10">
                  {material.type === "pdf" ? (
                    <FileText className="w-6 h-6 text-primary" />
                  ) : (
                    <Youtube className="w-6 h-6 text-red-500" />
                  )}
                </div>
                <Button
                  variant="ghost"
                  size="icon"
                  className="text-muted-foreground hover:text-destructive"
                  onClick={() => handleDelete(material.id)}
                >
                  <Trash2 className="w-4 h-4" />
                </Button>
              </CardHeader>
              <CardContent>
                <CardTitle className="text-lg font-semibold mb-2 line-clamp-1">
                  {material.title}
                </CardTitle>
                <CardDescription className="flex items-center gap-4 text-xs">
                  <span>{new Date(material.created_at).toLocaleDateString()}</span>
                </CardDescription>
                <Button variant="secondary" className="w-full mt-4 gap-2" asChild>
                  <a href={material.url} target="_blank" rel="noopener noreferrer">
                    <ExternalLink className="w-4 h-4" />
                    Open
                  </a>
                </Button>
              </CardContent>
            </Card>
          </motion.div>
        ))}

        {filteredMaterials.length === 0 && (
          <div className="col-span-full text-center py-12 text-muted-foreground">
            No materials found. Upload a PDF or add a YouTube link to get started.
          </div>
        )}
      </motion.div>
    </motion.div>
  );
};

import { motion } from "framer-motion";
