import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Switch } from "@/components/ui/switch";
import { Plus, Trash2, Save, GraduationCap, ChevronDown, ChevronRight, CheckCircle2 } from "lucide-react";
import { toast } from "sonner";
import { Label } from "@/components/ui/label";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible";

interface Question {
    id: string;
    text: string;
    options: string[];
    correctAnswer: number; // index
}

interface QuizTemplate {
    id: string;
    title: string;
    description: string;
    is_published: boolean;
    xp_reward: number;
    questions: Question[]; // Stored as JSONB
}

const QuizManager = () => {
    const [quizzes, setQuizzes] = useState<QuizTemplate[]>([]);
    const [isEditing, setIsEditing] = useState(false);
    const [currentQuiz, setCurrentQuiz] = useState<Partial<QuizTemplate>>({
        title: "",
        description: "",
        questions: []
    });

    useEffect(() => {
        fetchQuizzes();
    }, []);

    const fetchQuizzes = async () => {
        const { data, error } = await supabase.from('quizzes').select('*').order('created_at', { ascending: false });
        if (error) toast.error("Error loading quizzes");
        else setQuizzes((data as any[])?.map(q => ({
            ...q,
            questions: q.questions as Question[]
        })) || []);
    };

    const handleSave = async () => {
        if (!currentQuiz.title) return toast.error("Title required");

        const { data: { user } } = await supabase.auth.getUser();
        if (!user) return;

        const payload = {
            title: currentQuiz.title,
            description: currentQuiz.description,
            questions: currentQuiz.questions as any, // Cast to JSON
            teacher_id: user.id,
            is_published: currentQuiz.is_published || false,
            xp_reward: currentQuiz.xp_reward || 100
        };

        const { error } = await supabase
            .from('quizzes')
            .upsert(currentQuiz.id ? { id: currentQuiz.id, ...payload } : payload);

        if (error) toast.error("Failed to save quiz");
        else {
            toast.success("Quiz saved!");
            setIsEditing(false);
            setCurrentQuiz({ title: "", description: "", questions: [] });
            fetchQuizzes();
        }
    };

    const addQuestion = () => {
        const newQ: Question = {
            id: Math.random().toString(36).substr(2, 9),
            text: "New Question",
            options: ["Option 1", "Option 2", "Option 3", "Option 4"],
            correctAnswer: 0
        };
        setCurrentQuiz(prev => ({
            ...prev,
            questions: [...(prev.questions || []), newQ]
        }));
    };

    const updateQuestion = (index: number, field: keyof Question, value: any) => {
        const newQuestions = [...(currentQuiz.questions || [])];
        newQuestions[index] = { ...newQuestions[index], [field]: value };
        setCurrentQuiz(prev => ({ ...prev, questions: newQuestions }));
    };

    const updateOption = (qIndex: number, oIndex: number, value: string) => {
        const newQuestions = [...(currentQuiz.questions || [])];
        newQuestions[qIndex].options[oIndex] = value;
        setCurrentQuiz(prev => ({ ...prev, questions: newQuestions }));
    };

    if (isEditing) {
        return (
            <div className="space-y-6 max-w-4xl mx-auto">
                <div className="flex justify-between items-center">
                    <h2 className="text-2xl font-bold">Edit Quiz</h2>
                    <div className="flex gap-2">
                        <Button variant="outline" onClick={() => setIsEditing(false)}>Cancel</Button>
                        <Button onClick={handleSave}><Save className="w-4 h-4 mr-2" /> Save Form</Button>
                    </div>
                </div>

                <Card className="glass-card">
                    <CardContent className="space-y-4 pt-6">
                        <div className="space-y-2">
                            <Label>Quiz Title</Label>
                            <Input
                                value={currentQuiz.title}
                                onChange={e => setCurrentQuiz(prev => ({ ...prev, title: e.target.value }))}
                            />
                        </div>
                        <div className="space-y-2">
                            <Label>Description</Label>
                            <Textarea
                                value={currentQuiz.description}
                                onChange={e => setCurrentQuiz(prev => ({ ...prev, description: e.target.value }))}
                            />
                        </div>
                        <div className="space-y-2">
                            <Label>XP Reward</Label>
                            <Input
                                type="number"
                                value={currentQuiz.xp_reward || 100}
                                onChange={e => setCurrentQuiz(prev => ({ ...prev, xp_reward: Number(e.target.value) }))}
                            />
                        </div>
                        <div className="flex items-center space-x-2">
                            <Switch
                                checked={currentQuiz.is_published}
                                onCheckedChange={checked => setCurrentQuiz(prev => ({ ...prev, is_published: checked }))}
                            />
                            <Label>Published (Visible to students)</Label>
                        </div>
                    </CardContent>
                </Card>

                <div className="space-y-4">
                    <div className="flex justify-between items-center">
                        <h3 className="text-xl font-semibold">Questions ({currentQuiz.questions?.length})</h3>
                        <Button variant="secondary" onClick={addQuestion}><Plus className="w-4 h-4 mr-2" /> Add Question</Button>
                    </div>

                    {currentQuiz.questions?.map((q, qIndex) => (
                        <Card key={q.id || qIndex} className="glass-card">
                            <CardHeader className="py-4">
                                <div className="flex justify-between">
                                    <span className="font-mono text-muted-foreground">Q{qIndex + 1}</span>
                                    <Button
                                        variant="ghost"
                                        size="sm"
                                        className="text-destructive h-8"
                                        onClick={() => {
                                            const qs = [...(currentQuiz.questions || [])];
                                            qs.splice(qIndex, 1);
                                            setCurrentQuiz(prev => ({ ...prev, questions: qs }));
                                        }}
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </Button>
                                </div>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <Input
                                    value={q.text}
                                    onChange={e => updateQuestion(qIndex, 'text', e.target.value)}
                                    className="font-medium text-lg"
                                />
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    {q.options.map((opt, oIndex) => (
                                        <div key={oIndex} className="flex gap-2 items-center">
                                            <div
                                                className={`w-6 h-6 rounded-full border flex items-center justify-center cursor-pointer transition-colors ${q.correctAnswer === oIndex ? "bg-primary border-primary text-primary-foreground" : "border-muted-foreground/50 hover:border-primary"}`}
                                                onClick={() => updateQuestion(qIndex, 'correctAnswer', oIndex)}
                                            >
                                                {q.correctAnswer === oIndex && <CheckCircle2 className="w-4 h-4" />}
                                            </div>
                                            <Input
                                                value={opt}
                                                onChange={e => updateOption(qIndex, oIndex, e.target.value)}
                                            />
                                        </div>
                                    ))}
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="space-y-6 max-w-5xl mx-auto">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-3xl font-bold">Quiz Manager</h1>
                    <p className="text-muted-foreground">Create and assess student knowledge</p>
                </div>
                <Button onClick={() => {
                    setCurrentQuiz({ title: "", description: "", questions: [], is_published: false });
                    setIsEditing(true);
                }}>
                    <Plus className="w-4 h-4 mr-2" /> Create Quiz
                </Button>
            </div>

            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                {quizzes.map(quiz => (
                    <Card key={quiz.id} className="glass-card hover:border-primary/50 transition-all cursor-pointer group" onClick={() => {
                        setCurrentQuiz(quiz);
                        setIsEditing(true);
                    }}>
                        <CardHeader>
                            <CardTitle className="truncate">{quiz.title}</CardTitle>
                            <CardDescription className="line-clamp-2">{quiz.description || "No description"}</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <div className="flex justify-between items-center text-sm text-muted-foreground">
                                <span className={quiz.is_published ? "text-green-500 font-medium" : "text-yellow-500"}>
                                    {quiz.is_published ? "Published" : "Draft"}
                                </span>
                                <span>{quiz.questions?.length || 0} Questions</span>
                            </div>
                        </CardContent>
                    </Card>
                ))}
            </div>
        </div>
    );
};

export default QuizManager;

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Search, Trophy, Flame, User as UserIcon, PlusCircle } from "lucide-react";
import { toast } from "sonner";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";

interface Student {
    id: string;
    display_name: string;
    email: string;
    total_xp: number;
    streak_count: number;
    avatar_url: string;
}

const StudentAnalytics = () => {
    const [students, setStudents] = useState<Student[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState("");
    const [selectedStudent, setSelectedStudent] = useState<Student | null>(null);
    const [xpAward, setXpAward] = useState(100);
    const [isDialogOpen, setIsDialogOpen] = useState(false);

    // Status log for debugging
    const [statusLog, setStatusLog] = useState<string[]>([]);
    const [currentUserRole, setCurrentUserRole] = useState<string>("loading...");

    useEffect(() => {
        fetchStudents();
        checkUserRole();
    }, []);

    const checkUserRole = async () => {
        const { data: { user } } = await supabase.auth.getUser();
        if (user) {
            const { data } = await supabase.from('profiles').select('role').eq('id', user.id).single();
            setCurrentUserRole(data?.role || "no-role");
        }
    };

    useEffect(() => {
        if (!isDialogOpen) setStatusLog([]);
    }, [isDialogOpen]);

    const addLog = (msg: string) => setStatusLog(prev => [...prev, `${new Date().toLocaleTimeString()}: ${msg}`]);

    const fetchStudents = async () => {
        try {
            // Fetch users with role 'student' or null
            const { data, error } = await supabase
                .from('profiles')
                .select('*')
                .or('role.eq.student,role.is.null');

            if (error) throw error;
            setStudents((data as any[]) || []);
        } catch (error) {
            console.error("Fetch error:", error);
            toast.error("Failed to load students");
        } finally {
            setLoading(false);
        }
    };

    const handleAwardXP = async () => {
        if (!selectedStudent) return;

        try {
            addLog(`Starting Award Process...`);
            addLog(`Target: ${selectedStudent.display_name} (${selectedStudent.id})`);
            addLog(`Amount: ${xpAward}`);

            // Cast amount to number just in case
            const amount = Number(xpAward);

            console.log("Awarding XP via RPC:", { target_id: selectedStudent.id, amount });

            // Try using the secure RPC function
            const { data, error } = await supabase.rpc('award_xp', {
                target_id: selectedStudent.id,
                amount: amount
            });

            if (error) {
                addLog(`RPC ERROR: ${error.message}`);
                addLog(`Code: ${error.code}`);
                console.error("RPC Error:", error);
                throw new Error(error.message || "Failed to award XP via RPC");
            }

            addLog(`SUCCESS! New XP Data: ${JSON.stringify(data)}`);
            console.log("Award XP Success:", data);

            // Supabase RPC returns JSON, check structure
            const resultData = data as any;
            const newTotalXP = resultData?.new_xp || ((selectedStudent.total_xp || 0) + amount);

            toast.success(`Awarded ${amount} XP to ${selectedStudent.display_name}`);
            setStudents(prev => prev.map(s => s.id === selectedStudent.id ? { ...s, total_xp: newTotalXP } : s));

            addLog("Closing dialog in 2s...");
            setTimeout(() => {
                setIsDialogOpen(false);
            }, 2000);

        } catch (error: any) {
            console.error("Critical Error awarding XP:", error);
            addLog(`CRITICAL FAILURE: ${error.message}`);
            toast.error(`Error: ${error.message || "Operation failed"}`);
        }
    };

    const filteredStudents = students.filter(s =>
        (s.display_name?.toLowerCase() || "").includes(searchTerm.toLowerCase()) ||
        (s.email?.toLowerCase() || "").includes(searchTerm.toLowerCase())
    );

    return (
        <div className="space-y-6 max-w-6xl mx-auto">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-bold">Student Analytics</h1>
                    <p className="text-muted-foreground">Monitor performance and award achievements</p>
                </div>
                <div className="bg-slate-800 text-slate-200 px-3 py-1 rounded-full text-xs font-mono border border-slate-700">
                    Your Role: <span className="text-primary font-bold">{currentUserRole}</span>
                </div>
            </div>

            <Card className="glass-card">
                <CardHeader>
                    <div className="flex items-center justify-between">
                        <CardTitle>Student Registry</CardTitle>
                        <div className="relative w-full max-w-sm">
                            <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                            <Input
                                placeholder="Search by name or email..."
                                className="pl-8"
                                value={searchTerm}
                                onChange={e => setSearchTerm(e.target.value)}
                            />
                        </div>
                    </div>
                </CardHeader>
                <CardContent>
                    <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead>Student</TableHead>
                                <TableHead>Status</TableHead>
                                <TableHead>XP</TableHead>
                                <TableHead>Streak</TableHead>
                                <TableHead className="text-right">Actions</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {filteredStudents.map(student => (
                                <TableRow key={student.id}>
                                    <TableCell className="flex items-center gap-3">
                                        <Avatar>
                                            <AvatarImage src={student.avatar_url} />
                                            <AvatarFallback><UserIcon className="w-4 h-4" /></AvatarFallback>
                                        </Avatar>
                                        <div>
                                            <div className="font-medium">{student.display_name || "Unknown"}</div>
                                            <div className="text-xs text-muted-foreground">{student.email}</div>
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <div className="inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 border-transparent bg-primary/10 text-primary shadow hover:bg-primary/20">
                                            Active
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex items-center gap-1 font-mono text-primary">
                                            <Trophy className="w-3 h-3" />
                                            {student.total_xp || 0}
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex items-center gap-1 font-mono text-orange-500">
                                            <Flame className="w-3 h-3" />
                                            {student.streak_count || 0}
                                        </div>
                                    </TableCell>
                                    <TableCell className="text-right">
                                        <Button
                                            size="sm"
                                            variant="outline"
                                            onClick={() => {
                                                setSelectedStudent(student);
                                                setIsDialogOpen(true);
                                                setXpAward(100);
                                                setStatusLog([]);
                                            }}
                                        >
                                            <PlusCircle className="w-3 h-3 mr-1" /> Award XP
                                        </Button>
                                    </TableCell>
                                </TableRow>
                            ))}
                        </TableBody>
                    </Table>
                </CardContent>
            </Card>

            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Award XP to {selectedStudent?.display_name}</DialogTitle>
                    </DialogHeader>
                    <div className="py-4 space-y-4">
                        <div>
                            <Label>XP Amount</Label>
                            <Input
                                type="number"
                                value={xpAward}
                                onChange={e => setXpAward(Number(e.target.value))}
                            />
                        </div>

                        {/* Visual Status Log */}
                        <div className="rounded-md border bg-slate-950 p-4">
                            <div className="flex justify-between items-center mb-2">
                                <p className="text-xs font-medium text-slate-400">Operation Status</p>
                                <span className="text-[10px] text-slate-600">v1.2 Debug</span>
                            </div>
                            <div className="h-[100px] w-full overflow-y-auto font-mono text-xs text-green-400 space-y-1">
                                {statusLog.length === 0 ? (
                                    <span className="text-slate-600 opacity-50">Waiting for command...</span>
                                ) : (
                                    statusLog.map((log, i) => (
                                        <div key={i} className="border-b border-green-900/30 pb-1 last:border-0 break-words">
                                            {log}
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    </div>
                    <DialogFooter>
                        <Button onClick={handleAwardXP} className="w-full">
                            Confirm Award
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
};

export default StudentAnalytics;

